28	  // Phase 1: red lines collapse out, staggered.
29	  const collapseStart = Math.round(durationInFrames * 0.12);
30	  const collapseStagger = 12;
31	  const collapseDur = 18;
32	  const removedIndexes = lines
33	    .map((l, i) => (l.kind === "removed" ? i : -1))
34	    .filter((i) => i >= 0);
35	
36	  // Phase 2: green lines type in, one after another.
37	  const typingStart =
38	    collapseStart + removedIndexes.length * collapseStagger + collapseDur + 10;
39	  const addedIndexes = lines
40	    .map((l, i) => (l.kind === "added" ? i : -1))
41	    .filter((i) => i >= 0);
42	  const typeStarts = new Map<number, { start: number; dur: number }>();
43	  let cursor = typingStart;
44	  for (const i of addedIndexes) {
45	    const dur = Math.max(18, Math.ceil(lines[i].text.length / TYPE_CHARS_PER_FRAME));
46	    typeStarts.set(i, { start: cursor, dur });
47	    cursor += dur + 6;
48	  }
49	  const typingDone = cursor;
50	
